final:
module RefModule(
    input clk,
    input [7:0] A,
    input [7:0] B,
    input [1:0] operation,
    output reg [15:0] result
);reg [15:0] final_sig;

    always @(posedge clk) begin
        case(operation)
            2'b00: // addition
                final_sig = {8'b0, A} + {8'b0, B};
            2'b01: // subtraction
                final_sig = {8'b0, A} - {8'b0, B};
            2'b10: // multiplication
                final_sig = {16'b0, A} * {16'b0, B};
            2'b11: // division
                final_sig = {16'b0, A} / {16'b0, B};
        endcase

        result <= final_sig;
    end
endmodule
